"use client";

import Image from "next/image";

interface Stat {
  value: string;
  label: string;
}

interface DynamicBehindTheWorkSectionProps {
  data: {
    title: string;
    description: string;
    stats: Stat[];
    images: {
      left: string;
      center: string;
      right: string;
    };
  };
}

export function DynamicBehindTheWorkSection({
  data,
}: DynamicBehindTheWorkSectionProps) {
  return (
    <section className="w-full bg-gray-50 py-16 md:py-24">
      <div className="mx-auto w-full max-w-[1400px] px-4 md:px-6">
        <div className="grid gap-12 lg:grid-cols-2">
          {/* Left Content */}
          <div className="flex flex-col justify-center">
            <h2 className="mb-6 text-4xl font-bold text-gray-900">
              {data.title}
            </h2>

            {data.description && (
              <p className="mb-8 text-lg text-gray-600 leading-relaxed">
                {data.description}
              </p>
            )}

            {/* Stats */}
            <div className="grid gap-6 md:grid-cols-3">
              {data.stats.map((stat, idx) => (
                <div key={idx} className="rounded-lg bg-white p-6 shadow-sm">
                  <div className="text-3xl font-bold text-orange-500">
                    {stat.value}
                  </div>
                  <div className="mt-2 text-sm text-gray-600">{stat.label}</div>
                </div>
              ))}
            </div>
          </div>

          {/* Right Images */}
          <div className="flex items-center justify-center gap-4">
            {data.images.left && (
              <div className="relative h-80 w-24 overflow-hidden rounded-lg">
                <Image
                  src={data.images.left}
                  alt="Left image"
                  fill
                  className="object-cover"
                />
              </div>
            )}

            {data.images.center && (
              <div className="relative h-96 w-32 overflow-hidden rounded-lg">
                <Image
                  src={data.images.center}
                  alt="Center image"
                  fill
                  className="object-cover"
                />
              </div>
            )}

            {data.images.right && (
              <div className="relative h-80 w-24 overflow-hidden rounded-lg">
                <Image
                  src={data.images.right}
                  alt="Right image"
                  fill
                  className="object-cover"
                />
              </div>
            )}
          </div>
        </div>
      </div>
    </section>
  );
}
