"use client";

import Image from "next/image";
import Link from "next/link";
import { ArrowRight } from "lucide-react";

interface FeatureSectionData {
  enabled: boolean;
  layout: "image-left" | "image-right";
  image: string;
  title: string;
  description: string;
  buttonText: string;
  buttonUrl: string;
  backgroundColor: string;
}

interface DynamicFeatureSectionProps {
  data: FeatureSectionData;
}

export function DynamicFeatureSection({ data }: DynamicFeatureSectionProps) {
  if (!data.enabled) return null;

  const isImageLeft = data.layout === "image-left";

  return (
    <section
      className="py-16 md:py-24"
      style={{ backgroundColor: data.backgroundColor }}
    >
      <div className="container mx-auto px-4">
        <div
          className={`grid items-center gap-8 md:gap-12 lg:gap-16 ${
            isImageLeft ? "md:grid-cols-2" : "md:grid-cols-2"
          }`}
        >
          {/* Image */}
          <div
            className={`relative ${
              isImageLeft ? "md:order-1" : "md:order-2"
            }`}
          >
            <div className="relative aspect-[4/3] w-full overflow-hidden rounded-2xl">
              {data.image ? (
                <Image
                  src={data.image}
                  alt={data.title}
                  fill
                  className="object-cover"
                  sizes="(max-width: 768px) 100vw, 50vw"
                />
              ) : (
                <div className="flex h-full items-center justify-center bg-gray-200">
                  <p className="text-gray-400">No image uploaded</p>
                </div>
              )}
            </div>
          </div>

          {/* Content */}
          <div
            className={`${
              isImageLeft ? "md:order-2" : "md:order-1"
            }`}
          >
            <h2 className="mb-6 text-3xl font-bold leading-tight text-gray-900 md:text-4xl lg:text-5xl">
              {data.title}
            </h2>
            <p className="mb-8 text-base leading-relaxed text-gray-700 md:text-lg">
              {data.description}
            </p>
            <Link
              href={data.buttonUrl}
              className="inline-flex items-center gap-2 rounded-full bg-yellow-400 px-8 py-3 font-semibold text-gray-900 transition-all hover:bg-yellow-500 hover:gap-3"
            >
              {data.buttonText}
              <ArrowRight className="h-5 w-5" />
            </Link>
          </div>
        </div>
      </div>
    </section>
  );
}
