"use client";

import Image from "next/image";
import Link from "next/link";

interface DynamicHeroSectionProps {
  data: {
    backgroundImage: string;
    title: string;
    highlightedText: string;
    description: string;
    buttonText: string;
    buttonUrl: string;
  };
}

export function DynamicHeroSection({ data }: DynamicHeroSectionProps) {
  const titleParts = data.title.split("\n");

  return (
    <section className="relative min-h-screen w-full overflow-hidden bg-black">
      {/* Background Image */}
      <div className="absolute inset-0">
        <Image
          src={data.backgroundImage}
          alt="Hero background"
          fill
          className="object-cover opacity-40"
          priority
        />
        <div className="absolute inset-0 bg-gradient-to-r from-black via-black/50 to-transparent" />
      </div>

      {/* Content */}
      <div className="relative z-10 flex min-h-screen items-center">
        <div className="mx-auto w-full max-w-[1400px] px-4 md:px-6">
          <div className="max-w-2xl">
            <h1 className="mb-4 text-5xl font-bold leading-tight text-white md:text-6xl lg:text-7xl">
              {titleParts.map((part, idx) => (
                <div key={idx}>{part}</div>
              ))}
              <span className="block bg-gradient-to-r from-orange-400 to-orange-500 bg-clip-text text-transparent">
                {data.highlightedText}
              </span>
            </h1>

            {data.description && (
              <p className="mb-8 text-lg text-gray-300 md:text-xl">
                {data.description}
              </p>
            )}

            <Link
              href={data.buttonUrl}
              className="inline-block rounded-lg bg-gradient-to-r from-orange-400 to-orange-500 px-8 py-3 font-semibold text-white transition-all hover:from-orange-500 hover:to-orange-600"
            >
              {data.buttonText}
            </Link>
          </div>
        </div>
      </div>
    </section>
  );
}
